80	    #[track_caller]
81	    pub(super) fn bind_new_task<T>(
82	        me: &Arc<Self>,
83	        future: T,
84	        id: task::Id,
85	        spawned_at: SpawnLocation,
86	    ) -> JoinHandle<T::Output>
87	    where
88	        T: Future + Send + 'static,
89	        T::Output: Send + 'static,
90	    {
