281	    pub(super) fn try_read_output(self, dst: &mut Poll<super::Result<T::Output>>, waker: &Waker) {
282	        if can_read_output(self.header(), self.trailer(), waker) {
283	            *dst = Poll::Ready(self.core().take_output());
284	        }
