22	impl<T: 'static> Shared<T> {
23	    /// Pushes several values into the queue.
24	    ///
25	    /// # Safety
26	    ///
27	    /// Must be called with the same `Synced` instance returned by `Inject::new`
28	    #[inline]
29	    pub(crate) unsafe fn push_batch<L, I>(&self, shared: L, mut iter: I)
30	    where
31	        L: Lock<Synced>,
32	        I: Iterator<Item = task::Notified<T>>,
33	    {
34	        let first = match iter.next() {
35	            Some(first) => first.into_raw(),
36	            None => return,
37	        };
38	
39	        // Link up all the tasks.
40	        let mut prev = first;
41	        let mut counter = 1;
42	
43	        // We are going to be called with an `std::iter::Chain`, and that
44	        // iterator overrides `for_each` to something that is easier for the
45	        // compiler to optimize than a loop.
46	        iter.for_each(|next| {
47	            let next = next.into_raw();
48	
49	            // safety: Holding the Notified for a task guarantees exclusive
50	            // access to the `queue_next` field.
51	            unsafe { prev.set_queue_next(Some(next)) };
52	            prev = next;
53	            counter += 1;
54	        });
55	
56	        // Now that the tasks are linked together, insert them into the
57	        // linked list.
58	        //
59	        // Safety: exactly the same safety requirements as `push_batch` method.
60	        unsafe {
61	            self.push_batch_inner(shared, first, prev, counter);
62	        }
63	    }
64	
65	    /// Inserts several tasks that have been linked together into the queue.
66	    ///
67	    /// The provided head and tail may be the same task. In this case, a
68	    /// single task is inserted.
69	    ///
70	    /// # Safety
71	    ///
72	    /// Must be called with the same `Synced` instance returned by `Inject::new`
73	    #[inline]
74	    unsafe fn push_batch_inner<L>(
75	        &self,
76	        shared: L,
77	        batch_head: task::RawTask,
78	        batch_tail: task::RawTask,
79	        num: usize,
80	    ) where
81	        L: Lock<Synced>,
82	    {
83	        debug_assert!(unsafe { batch_tail.get_queue_next().is_none() });
84	
85	        let mut synced = shared.lock();
86	
87	        if synced.as_mut().is_closed {
88	            drop(synced);
89	
90	            let mut curr = Some(batch_head);
91	
92	            while let Some(task) = curr {
93	                // Safety: exactly the same safety requirements as `push_batch_inner`.
94	                curr = unsafe { task.get_queue_next() };
95	
96	                let _ = unsafe { task::Notified::<T>::from_raw(task) };
97	            }
98	
99	            return;
100	        }
101	
102	        let synced = synced.as_mut();
103	
104	        if let Some(tail) = synced.tail {
105	            unsafe {
106	                tail.set_queue_next(Some(batch_head));
107	            }
108	        } else {
109	            synced.head = Some(batch_head);
110	        }
111	
112	        synced.tail = Some(batch_tail);
113	
114	        // Increment the count.
115	        //
116	        // safety: All updates to the len atomic are guarded by the mutex. As
117	        // such, a non-atomic load followed by a store is safe.
118	        let len = unsafe { self.len.unsync_load() };
119	
120	        self.len.store(len + num, Release);
121	    }
122	}
